  1	import * as React from 'react';
  2	import { resourceStatus as getDefaultResourceStatus } from '@odf/shared/status/Resource';
  3	import { ResourceStatus } from '@openshift-console/dynamic-plugin-sdk';
  4	import Status from '@openshift-console/dynamic-plugin-sdk/lib/app/components/status/Status';
  5	import classNames from 'classnames';
  6	import { Link } from 'react-router-dom-v5-compat';
  7	import {
  8	  Breadcrumb,
  9	  BreadcrumbItem,
 10	  Split,
 11	  SplitItem,
 12	  TextContent,
 13	  Text,
 14	  TextVariants,
 15	} from '@patternfly/react-core';
 16	import { K8sResourceKind } from '../types/k8s';
 17	import './page-heading.scss';
 18	import '../style.scss';
 19	
 20	type BreadCrumbsProps = {
 21	  breadcrumbs: { name: string; path: string }[];
 22	};
 23	
 24	const BreadCrumbs: React.FC<BreadCrumbsProps> = ({ breadcrumbs }) => (
 25	  <Breadcrumb className="odf-breadcrumbs-link">
 26	    {breadcrumbs.map((crumb, i, { length }) => {
 27	      const isLast = i === length - 1;
 28	
 29	      return (
 30	        <BreadcrumbItem key={i} isActive={isLast}>
 31	          {isLast ? (
 32	            crumb.name
 33	          ) : (
 34	            <Link
 35	              className="pf-v6-c-breadcrumb__link"
 36	              to={crumb.path}
 37	              data-test-id={`breadcrumb-link-${i}`}
 38	            >
 39	              {crumb.name}
 40	            </Link>
 41	          )}
 42	        </BreadcrumbItem>
 43	      );
 44	    })}
 45	  </Breadcrumb>
 46	);
 47	
 48	type PageHeadingProps = {
 49	  breadcrumbs?: { name: string; path: string }[];
 50	  style?: object;
 51	  title?: string | JSX.Element;
 52	  badge?: React.ReactNode;
 53	  className?: string;
 54	  actions?: Function;
 55	  resource?: K8sResourceKind;
 56	  getResourceStatus?: (resource: K8sResourceKind) => string;
 57	  centerText?: boolean;
 58	  hasUnderline?: boolean;
 59	};
 60	
 61	const PageHeading: React.FC<PageHeadingProps> = (props) => {
 62	  const {
 63	    title,
 64	    breadcrumbs,
 65	    style,
 66	    badge,
 67	    className,
 68	    actions,
 69	    resource,
 70	    getResourceStatus,
 71	    centerText,
 72	    hasUnderline = true,
 73	  } = props;
 74	  const resourceTitle = title;
 75	  const showBreadcrumbs = !!breadcrumbs;
 76	  const showActions = !!actions;
 77	
 78	  const resourceStatus = resource
 79	    ? getResourceStatus
 80	      ? getResourceStatus(resource)
 81	      : getDefaultResourceStatus(resource)
 82	    : null;
 83	  return (
 84	    <div
 85	      className={classNames(
 86	        'odf-title',
 87	        'odf-m-nav-title',
 88	        hasUnderline && 'odf-m-nav-title--detail',
 89	        { 'odf-m-nav-title--breadcrumbs': showBreadcrumbs },
 90	        className
 91	      )}
 92	      style={style}
 93	    >
 94	      {showBreadcrumbs && (
 95	        <Split style={{ alignItems: 'baseline' }} className="odf-breadcrumbs">
 96	          <SplitItem isFilled>
 97	            <BreadCrumbs breadcrumbs={breadcrumbs} />
 98	          </SplitItem>
 99	          {badge && (
100	            <SplitItem>
101	              <span className="odf-m-pane__heading-badge">{badge}</span>
102	            </SplitItem>
103	          )}
104	        </Split>
105	      )}
106	      <div className="odf-title-details">
107	        <TextContent
108	          className={classNames({ 'odf-m-pane__heading--center': centerText })}
109	        >
110	          <Text component={TextVariants.h1} className="odf-resource-item">
111	            <span
112	              data-test-id="resource-title"
113	              className="odf-resource-item__resource-name odf-title-status"
114	            >
115	              {resourceTitle}
116	              {resourceStatus && (
117	                <ResourceStatus additionalClassNames="hidden-xs">
118	                  <Status status={resourceStatus} />
119	                </ResourceStatus>
120	              )}
121	            </span>
122	          </Text>
123	        </TextContent>
124	        {showActions && (
125	          <div className="odf-actions" data-test-id="details-actions">
126	            {actions()}
127	          </div>
128	        )}
129	      </div>
130	      {props.children}
131	    </div>
132	  );
133	};
134	
135	export default PageHeading;
136	
137	export type SectionHeadingProps = {
138	  children?: any;
139	  style?: any;
140	  text: string;
141	  required?: boolean;
142	  id?: string;
143	};
144	
145	export const SectionHeading: React.FC<SectionHeadingProps> = ({
146	  text,
147	  children,
148	  style,
149	  required,
150	  id,
151	}) => (
152	  <TextContent
153	    className="odf-section-heading"
154	    style={style}
155	    data-test-section-heading={text}
156	    id={id}
157	  >
158	    <Text component={TextVariants.h2}>
159	      <span
160	        className={classNames({
161	          'odf-required': required,
162	        })}
163	      >
164	        {text}
165	      </span>
166	      {children}
167	    </Text>
168	  </TextContent>
169	);

